import React, { useEffect, useState } from "react";
import database from "./firebase";
import { ref, onValue, set } from "firebase/database";
import { LineChart, Line, XAxis, YAxis, Tooltip, CartesianGrid, Legend } from "recharts";

function App() {
  const [leftFootData, setLeftFootData] = useState([]);

  const handleStart = () => {
    set(ref(database, "commands/recording"), true);
  };

  const handleStop = () => {
    set(ref(database, "commands/recording"), false);
  };

  useEffect(() => {
    const leftFootRef = ref(database, "leftFoot");
    onValue(leftFootRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const formatted = Object.entries(data).map(([ts, values]) => ({
          timestamp: ts,
          accel_x: values.accel_x || 0,
          accel_y: values.accel_y || 0,
          accel_z: values.accel_z || 0,
        }));
        setLeftFootData(formatted);
      }
    });
  }, []);

  return (
    <div>
      <h2>Left Foot Acceleration (X, Y, Z) vs Timestamp</h2>
      <LineChart width={700} height={350} data={leftFootData}>
        <CartesianGrid stroke="#ccc" />
        <XAxis dataKey="timestamp" />
        <YAxis />
        <Tooltip />
        <Legend />
        <Line type="monotone" dataKey="accel_x" stroke="#ff0000" name="Accel X" />
        <Line type="monotone" dataKey="accel_y" stroke="#00ff00" name="Accel Y" />
        <Line type="monotone" dataKey="accel_z" stroke="#0000ff" name="Accel Z" />
      </LineChart>

      <div style={{ marginTop: "20px" }}>
        <button onClick={handleStart}>Start Recording</button>
        <button onClick={handleStop} style={{ marginLeft: "10px" }}>Stop Recording</button>
      </div>
    </div>
  );
}

export default App;
